t.t:
/* Hero */
.page-hero { background: linear-gradient(135deg, var(--primary) 0%, #185FA5 100%); border-radius: 12px; padding: 36px 40px; margin-bottom: 28px; color: #fff; position: relative; overflow: hidden; }
.page-hero::after { content: ''; position: absolute; right: -40px; top: -40px; width: 220px; height: 220px; border-radius: 50%; background: rgba(255,255,255,0.05); }
.page-hero h1 { font-family: 'Source Serif 4', serif; font-size: 26px; font-weight: 600; margin-bottom: 8px; position: relative; }
.page-hero p { font-size: 14px; color: rgba(255,255,255,0.75); max-width: 500px; }
/* Search */
.search-wrap { position: relative; max-width: 380px; margin-bottom: 24px; }
.search-wrap input { width: 100%; padding: 9px 12px 9px 38px; border: 1px solid var(--border); border-radius: 6px; font-size: 13px; font-family: inherit; background: var(--bg-card); color: var(--text-primary); outline: none; transition: border 0.15s; }
.search-wrap input:focus { border-color: var(--primary); box-shadow: 0 0 0 3px rgba(15,76,129,0.08); }
.search-icon { position: absolute; left: 12px; top: 50%; transform: translateY(-50%); color: var(--text-muted); font-size: 14px; pointer-events: none; }
/* Grid */
.q-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(300px, 1fr)); gap: 18px; }
/* Card */
.q-card { background: var(--bg-card); border: 1px solid var(--border); border-radius: 10px; padding: 22px; display: flex; flex-direction: column; gap: 10px; transition: box-shadow 0.2s, transform 0.2s; }
.q-card:hover { box-shadow: 0 4px 18px rgba(15,76,129,0.10); transform: translateY(-2px); }
.q-card-icon { width: 42px; height: 42px; border-radius: 10px; background: var(--primary-light); color: var(--primary); font-size: 20px; display: flex; align-items: center; justify-content: center; flex-shrink: 0; }
.q-card-header { display: flex; align-items: center; gap: 12px; }
.q-card-title { font-size: 14.5px; font-weight: 600; color: var(--text-primary); line-height: 1.4; }
.q-card-desc { font-size: 13px; color: var(--text-muted); line-height: 1.5; display: -webkit-box; -webkit-line-clamp: 3; -webkit-box-orient: vertical; overflow: hidden; flex: 1; }
.q-card-footer { display: flex; align-items: center; justify-content: flex-end; margin-top: auto; padding-top: 12px; border-top: 1px solid var(--border); }
/* Empty state */
.empty-state { text-align: center; padding: 60px 20px; color: var(--text-muted); }
.empty-state .empty-icon { font-size: 40px; margin-bottom: 12px; }
.empty-state p { font-size: 15px; }

t.script:
function filterQuestionarios() {
    const q = document.getElementById('q-search').value.toLowerCase();
    document.querySelectorAll('.q-card').forEach(card => {
        const match = !q || (card.dataset.search || '').toLowerCase().includes(q);
        card.style.display = match ? '' : 'none';
    });
}
